import{_ as s,o as i,c as a,a2 as r}from"./chunks/framework.Cuq8tsM6.js";const g=JSON.parse('{"title":"Impression & Logistique","description":"","frontmatter":{"title":"Impression & Logistique"},"headers":[],"relativePath":"docs/fr/advertisers/printing-services.md","filePath":"docs/fr/advertisers/printing-services.md"}'),t={name:"docs/fr/advertisers/printing-services.md"};function n(o,e,l,c,d,u){return i(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="services-d-impression-et-logistique" tabindex="-1">Services d&#39;Impression et Logistique <a class="header-anchor" href="#services-d-impression-et-logistique" aria-label="Permalink to &quot;Services d&#39;Impression et Logistique&quot;">​</a></h1><p>getinside agit comme une centrale d&#39;achat pour mutualiser les volumes, réduire vos coûts et garantir une production responsable.</p><h2 id="🏭-une-qualite-certifiee" tabindex="-1">🏭 Une qualité certifiée <a class="header-anchor" href="#🏭-une-qualite-certifiee" aria-label="Permalink to &quot;🏭 Une qualité certifiée&quot;">​</a></h2><div class="gi-accent-box"><p style="margin:0 0 1.25rem;color:var(--vp-c-text-2);">Nous travaillons exclusivement avec un réseau de partenaires français engagés :</p><div class="gi-cert-row"><div class="gi-cert-item"><span class="gi-cert-icon">🇫🇷</span><strong>Made in France</strong><span>100% de la production en ateliers français.</span></div><div class="gi-cert-item"><span class="gi-cert-icon">🌱</span><strong>Éco-responsabilité</strong><span>Certification Imprim&#39;Vert &amp; Encres végétales.</span></div><div class="gi-cert-item"><span class="gi-cert-icon">✅</span><strong>Normes ISO</strong><span>ISO 9001 (Qualité) et ISO 14001 (Environnement).</span></div></div></div><h2 id="🚀-cas-d-usage-offres" tabindex="-1">🚀 Cas d&#39;usage &amp; Offres <a class="header-anchor" href="#🚀-cas-d-usage-offres" aria-label="Permalink to &quot;🚀 Cas d&#39;usage &amp; Offres&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>1. Pour vos campagnes (Sponsored Mail)</strong><p>Vous réservez une campagne chez un distributeur partenaire.</p><ul style="margin:0.5rem 0 0;padding-left:1.25rem;font-size:0.875rem;color:var(--vp-c-text-2);"><li>Nous imprimons vos supports.</li><li>Nous gérons l&#39;assemblage (ex: point de colle fugitive pour échantillon).</li><li>Nous livrons directement à l&#39;entrepôt du distributeur.</li></ul></div><div class="gi-value-card" style="border-color:var(--vp-c-brand-1);background:var(--gi-tint-blue-bg);"><strong style="color:var(--vp-c-brand-1);">2. Auto-promotion (Pour vous)</strong><p>Vous souhaitez imprimer vos propres cartes de remerciement ou flyers à insérer dans <strong>vos propres colis</strong> ?</p><ul style="margin:0.5rem 0 0;padding-left:1.25rem;font-size:0.875rem;color:var(--vp-c-text-2);"><li>Créez une campagne &quot;interne&quot; via la plateforme.</li><li>Bénéficiez de nos tarifs de groupe industriels.</li><li>Nous livrons les palettes chez vous.</li></ul></div></div><h2 id="modele-economique" tabindex="-1">Modèle Économique <a class="header-anchor" href="#modele-economique" aria-label="Permalink to &quot;Modèle Économique&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>💎 Transparence</strong><p>Le coût est affiché clairement lors de la configuration.</p></div><div class="gi-value-card"><strong>📦 Tout inclus</strong><p>Impression + Façonnage + Transport.</p></div><div class="gi-value-card"><strong>📉 Économies d&#39;échelle</strong><p>Plus le volume est important, plus le coût unitaire baisse.</p></div></div><h2 id="focus-notre-engagement-handicap" tabindex="-1">Focus : Notre engagement Handicap <a class="header-anchor" href="#focus-notre-engagement-handicap" aria-label="Permalink to &quot;Focus : Notre engagement Handicap&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>Partenariat Exclusif</strong><p>Pour toutes les opérations manuelles (assemblage, collage d&#39;échantillons, mise sous pli), nous travaillons exclusivement avec des <strong>Entreprises Adaptées (EA)</strong>.</p><p style="margin:0;">Ces structures emploient au moins <strong>80% de travailleurs en situation de handicap</strong> dans leurs effectifs de production.</p></div><div class="gi-value-card"><strong>Impact Social</strong><p>En confiant votre logistique à getinside, vous soutenez directement l&#39;insertion professionnelle et sociale de personnes souvent éloignées du marché du travail.</p><p style="margin:0;">Nos partenaires œuvrent notamment pour maintenir l&#39;emploi en milieu rural et accompagner la montée en compétences de leurs salariés.</p></div></div><div class="gi-info-box"><h4>Comment commander ?</h4><p>L&#39;option d&#39;impression vous est proposée automatiquement lors de la création d&#39;une campagne sur le SaaS.</p><p style="margin:0;">Pour une demande spécifique (formats spéciaux) : <a href="mailto:studio@getinside.fr">studio@getinside.fr</a></p></div>',11)])])}const m=s(t,[["render",n]]);export{g as __pageData,m as default};
